if (! function_exists('public_holidays')) {
    function public_holidays($country_code = null, $year = null, $timeout = null)
    {
        $country_code = strtoupper(trim($country_code ?? 'US'));
        $timeout = (int)($timeout ?? 15);
        $year = (int)($year ?? (int)date('Y'));

        if ($year < 2000 || $year > 2100) {
            $year = (int)date('Y');
        }

        // Nager.Date API — free, no key
        $url = 'https://date.nager.at/api/v3/PublicHolidays/' . $year . '/' . urlencode($country_code);

        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n",
                'ignore_errors' => true,
            ]
        ]);

        $response = @file_get_contents($url, false, $context);

        if ($response === false) {
            return ['success' => false, 'error' => 'Failed to reach Nager.Date API.'];
        }

        $data = json_decode($response, true);

        if ($data === null) {
            return ['success' => false, 'error' => 'Failed to parse API response.', 'raw' => mb_substr($response, 0, 300)];
        }

        // API may return error as array with status field
        if (isset($data['status']) && $data['status'] >= 400) {
            return ['success' => false, 'error' => $data['title'] ?? 'API error', 'detail' => $data['detail'] ?? ''];
        }

        if (!is_array($data)) {
            return ['success' => false, 'error' => 'Unexpected API response format.'];
        }

        // Process holidays
        $holidays = [];
        $by_month = [];
        $types_count = [];

        foreach ($data as $h) {
            $date = $h['date'] ?? '';
            $parsed_date = $date ? date_parse($date) : null;
            $month = $parsed_date ? (int)$parsed_date['month'] : 0;
            
            $entry = [
                'date' => $date,
                'name' => $h['name'] ?? '',
                'local_name' => $h['localName'] ?? ($h['name'] ?? ''),
                'country_code' => $h['countryCode'] ?? $country_code,
                'fixed' => (bool)($h['fixed'] ?? true),
                'global' => (bool)($h['global'] ?? true),
                'types' => $h['types'] ?? ['Public'],
                'day_of_week' => $date ? date('l', strtotime($date)) : '',
            ];
            
            $holidays[] = $entry;
            
            // Count by month
            if ($month > 0) {
                $by_month[$month] = ($by_month[$month] ?? 0) + 1;
            }
            
            // Count by type
            foreach ($entry['types'] as $t) {
                $types_count[$t] = ($types_count[$t] ?? 0) + 1;
            }
        }

        // Sort by date
        usort($holidays, fn($a, $b) => $a['date'] <=> $b['date']);

        // Upcoming holidays
        $today = date('Y-m-d');
        $upcoming = array_values(array_filter($holidays, fn($h) => $h['date'] >= $today));
        $next_holiday = $upcoming[0] ?? null;

        // Count fixed vs variable
        $fixed_count = count(array_filter($holidays, fn($h) => $h['fixed']));
        $variable_count = count($holidays) - $fixed_count;

        return [
            'success' => true,
            'country_code' => $country_code,
            'year' => $year,
            'total_holidays' => count($holidays),
            'fixed_vs_variable' => ['fixed' => $fixed_count, 'variable' => $variable_count],
            'by_month' => $by_month,
            'by_type' => $types_count,
            'next_holiday' => $next_holiday,
            'upcoming_count' => count($upcoming),
            'holidays' => $holidays,
        ];
    }
